import json
import pandas as pd
import re

# Load business data from JSON file path stored in var_call_aeEoXbsvtD9GmA5JrtBXwFLU
with open(var_call_aeEoXbsvtD9GmA5JrtBXwFLU, 'r') as f:
    businesses = json.load(f)

# Load review aggregates from var_call_HKKi8GXfABvvRYdKCz1rVXdH
review_aggs = var_call_HKKi8GXfABvvRYdKCz1rVXdH

# Build mapping from business_ref to (avg_rating, review_count)
rev_map = {}
for r in review_aggs:
    br = r.get('business_ref')
    try:
        avg = float(r.get('avg_rating'))
    except:
        avg = None
    try:
        cnt = int(r.get('review_count'))
    except:
        cnt = 0
    rev_map[br] = {'avg_rating': avg, 'review_count': cnt}

# Helper to extract wifi value from attributes dict
def get_wifi(attr):
    if not isinstance(attr, dict):
        return None
    for key in ['WiFi', 'Wi-Fi', 'wifi']:
        if key in attr:
            val = attr[key]
            if val is None:
                return None
            # val might be a non-string like True/False or a string representation
            return str(val)
    return None

# Helper to determine if wifi offering counts as offered
def offers_wifi(wval):
    if wval is None:
        return False
    s = wval.lower()
    # Common indicators of offering
    if 'no' in s:
        return False
    if any(k in s for k in ['free', 'paid', 'limited', 'yes', 'true']):
        return True
    # fallback: if contains alphabetic, assume offering unless explicitly 'no'
    # but be conservative and return False
    return False

# Extract state from description using regex
state_counts = {}
state_businesses = {}  # state -> list of business dicts
for b in businesses:
    attr = b.get('attributes')
    wifi_val = get_wifi(attr)
    if not offers_wifi(wifi_val):
        continue
    desc = b.get('description') or ''
    state = None
    # try pattern: 'in <City>, XX,'
    m = re.search(r"in [^,]+,\s*([A-Z]{2})", desc)
    if m:
        state = m.group(1)
    else:
        # fallback: find last ', XX' pattern
        m2 = re.search(r",\s*([A-Z]{2})\b", desc)
        if m2:
            state = m2.group(1)
    if not state:
        continue
    state_counts[state] = state_counts.get(state, 0) + 1
    state_businesses.setdefault(state, []).append(b)

# Determine state with highest number of wifi-offering businesses
if not state_counts:
    result = {'state': None, 'wifi_business_count': 0, 'businesses_with_reviews_count': 0, 'avg_rating_weighted': None}
else:
    max_state = max(state_counts.items(), key=lambda x: x[1])[0]
    wifi_count = state_counts[max_state]
    bizs = state_businesses.get(max_state, [])
    # For those businesses, compute weighted average rating using review aggregates
    total_reviews = 0
    weighted_sum = 0.0
    bizs_with_reviews = 0
    for b in bizs:
        bid = b.get('business_id')
        if not bid:
            continue
        bref = bid.replace('businessid_', 'businessref_')
        if bref in rev_map and rev_map[bref]['avg_rating'] is not None:
            bizs_with_reviews += 1
            cnt = rev_map[bref]['review_count']
            avg = rev_map[bref]['avg_rating']
            total_reviews += cnt
            weighted_sum += avg * cnt
    if total_reviews > 0:
        avg_weighted = weighted_sum / total_reviews
    else:
        avg_weighted = None
    result = {'state': max_state, 'wifi_business_count': wifi_count, 'businesses_with_reviews_count': bizs_with_reviews, 'avg_rating_weighted': avg_weighted}

# Print result in required format as a JSON string
print("__RESULT__:")
print(json.dumps(result))

